#include <bits/stdc++.h>
using namespace std;

int n, a[105], b[105];
int f[105][100005];

int DFS(int k, int sum1, int sum2) {
    if (f[k][sum1 - sum2 + 50000] != INT_MAX) 
        return f[k][sum1 - sum2 + 50000];
    if (k == n) {
        if (sum1 == sum2) {
            return 0;
        }
        else {
            return INT_MIN;
        }
    }
    f[k][sum1 - sum2 + 50000] = max(
        DFS(k + 1, sum1 + a[k], sum2 + b[k]) + a[k] + b[k],
        DFS(k + 1, sum1, sum2)
    );
    return f[k][sum1 - sum2 + 50000];
}

int main() {
    cin >> n;
    for (int i = 0; i < n; i++) {
        cin >> a[i] >> b[i];
    }
    for (int i = 0; i < 105; i++) {
        for (int j = 0; j < 100005; j++) {
            f[i][j] = INT_MAX;
        }
    }
    cout << DFS(0, 0, 0) << endl;
    return 0;
}
